package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class FieldAttributesTest {

  private FieldAttributes fieldAttributes;
  private Field mockField;

  @BeforeEach
  void setUp() throws NoSuchFieldException {
    mockField = mock(Field.class);
    @SuppressWarnings("unchecked")
    Class<?> declaringClass = (Class<?>) (Class<?>) String.class;
    when(mockField.getDeclaringClass()).thenReturn(declaringClass);
    fieldAttributes = new FieldAttributes(mockField);
  }

  @Test
  void testGetDeclaringClass() {
    Class<?> declaringClass = fieldAttributes.getDeclaringClass();
    assertEquals(String.class, declaringClass);
  }
}
